const fs = require('fs');
const path = require('path');
const toolsRoot = '/home/node/.n8n/local-tools';
const tempRoot = path.join(toolsRoot, 'tmp');
const readableFilesRoot = '/home/node/.n8n-files';
const snapshotOutputRoot = path.join(readableFilesRoot, 'snapshots');
const toolDir = path.join(toolsRoot, 'pdf-to-png-converter');
const scriptPath = path.join(toolDir, 'convert-first-page.js');
const packagePath = path.join(toolDir, 'package.json');
const packageJson = {
  name: 'local-pdf-to-png-converter',
  private: true,
  version: '1.0.0',
  description: 'Local PDF to PNG converter for n8n Slack snapshots',
  license: 'UNLICENSED'
};
const script = [
  '#!/usr/bin/env node',
  "const fs = require('fs');",
  "const path = require('path');",
  "const { pdfToPng } = require('pdf-to-png-converter');",
  "const converterPackage = JSON.parse(",
  "  fs.readFileSync(path.join(__dirname, 'node_modules', 'pdf-to-png-converter', 'package.json'), 'utf8')",
  ");",
  'function getArg(name) {',
  '  const index = process.argv.indexOf(name);',
  '  return index >= 0 ? process.argv[index + 1] : undefined;',
  '}',
  'async function main() {',
  "  if (process.argv.includes('--healthcheck')) {",
  "    console.log(JSON.stringify({ ok: true, converterVersion: converterPackage.version, nodeVersion: process.version, scriptPath: __filename }));",
  '    return;',
  '  }',
  "  const inputPath = getArg('--input');",
  "  const outputPath = getArg('--output');",
  "  const viewportScale = Number(getArg('--viewport-scale') || '1.5');",
  '  if (!inputPath || !outputPath) {',
  "    throw new Error('Usage: convert-first-page.js --input <pdf> --output <png> [--viewport-scale <number>]');",
  '  }',
  '  if (!fs.existsSync(inputPath)) {',
  "    throw new Error('Input PDF not found: ' + inputPath);",
  '  }',
  '  const outputDir = path.dirname(outputPath);',
  '  fs.mkdirSync(outputDir, { recursive: true });',
  '  if (fs.existsSync(outputPath)) {',
  '    fs.unlinkSync(outputPath);',
  '  }',
  '  const pages = await pdfToPng(inputPath, {',
  '    outputFolder: outputDir,',
  '    pagesToProcess: [1],',
  '    viewportScale,',
  '    returnPageContent: false,',
  '    disableFontFace: false,',
  '    useSystemFonts: true,',
  '  });',
  '  const renderedPath = pages[0] && pages[0].path;',
  '  if (!pages.length || !renderedPath || !fs.existsSync(renderedPath)) {',
  "    throw new Error('Converter did not create the expected PNG output');",
  '  }',
  '  if (renderedPath !== outputPath) {',
  '    fs.copyFileSync(renderedPath, outputPath);',
  '  }',
  '  const stats = fs.statSync(outputPath);',
  "  console.log(JSON.stringify({ ok: true, outputPath, bytes: stats.size, pageCount: pages.length, converterVersion: converterPackage.version }));",
  '}',
  'main().catch((error) => {',
  "  console.error(error.stack || error.message || String(error));",
  '  process.exit(1);',
  '});',
].join('\n') + '\n';
fs.mkdirSync(toolsRoot, { recursive: true });
fs.mkdirSync(tempRoot, { recursive: true });
fs.mkdirSync(readableFilesRoot, { recursive: true });
fs.mkdirSync(snapshotOutputRoot, { recursive: true });
fs.mkdirSync(toolDir, { recursive: true });
fs.chmodSync(toolsRoot, 0o755);
fs.chmodSync(toolDir, 0o755);
fs.chmodSync(tempRoot, 0o777);
fs.chmodSync(readableFilesRoot, 0o755);
fs.chmodSync(snapshotOutputRoot, 0o777);
if (!fs.existsSync(packagePath)) {
  fs.writeFileSync(packagePath, JSON.stringify(packageJson, null, 2) + '\n');
}
if (!fs.existsSync(scriptPath)) {
  fs.writeFileSync(scriptPath, script);
}
fs.chmodSync(scriptPath, 0o755);
const tempProbe = path.join(tempRoot, '.write-test');
fs.writeFileSync(tempProbe, 'ok\n');
fs.unlinkSync(tempProbe);
const outputProbe = path.join(snapshotOutputRoot, '.write-test');
fs.writeFileSync(outputProbe, 'ok\n');
fs.unlinkSync(outputProbe);
console.log(JSON.stringify({ ok: true, toolsRoot, tempRoot, readableFilesRoot, snapshotOutputRoot, toolDir, scriptPath, packagePath, tempWritable: true, outputWritable: true }));
NODE

